18	  const merged = useMemo(() => {
19	    const q = new URLSearchParams(sp.toString());
20	    return q;
21	  }, [sp]);
22	
23	  function apply(nextAsOf: string) {
24	    const q = new URLSearchParams(merged.toString());
25	    if (!nextAsOf) {
26	      q.delete("asOf");
27	    } else {
