// ── Belief revision audit ledger ─────────────────────────────────────────
//
// Every committed revision (founder marks new evidence on a claim and
// confirms the propagation preview) appends one row here. The
// `preConfidenceSnapshot` is what makes time-replay work: replaying the
// ledger up to but not including a given event reconstructs the prior
// belief state exactly. `revertedAt` is the soft-delete: the public
// "/revisions/<id>" page renders an event regardless, but conclusion
// readers fall through to the previous non-reverted event.
model RevisionEvent {
  id             String  @id @default(cuid())
  organizationId String
  /// Plan id from the noosphere engine (sha256 over inputs+thresholds);
  /// duplicates indicate idempotent re-submits and are allowed.
  planId         String
  /// Founder who confirmed the revision in the preview modal.
  founderId      String

  /// JSON: [{ claim_id, weight, new_evidence }] — the RevisionInput batch.
  inputsJson     String
  /// JSON: full RevisionPlan.to_dict() — frozen at commit time.
  planJson       String
  /// JSON: { conclusion_id: confidence_before } — the before-snapshot.
  preConfidenceSnapshot String
  /// Conclusions whose confidence changed by > δ at commit time. Stored
  /// as a denormalised JSON array of conclusion ids so the UI can build
  /// the "updated" pill query without parsing planJson on every page
  /// render. Source of truth is still planJson.
  affectedConclusionIds String  @default("[]")

  /// `true` when the founder typed the K-cap confirmation phrase. Always
  /// `false` for revisions whose affected_count <= K; informational only.
  typedConfirmation Boolean @default(false)

  createdAt  DateTime  @default(now())
  revertedAt DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([organizationId, createdAt])
  @@index([planId])
}

// ── API keys for machine-to-machine auth (Dialectic auto-sync, scripts, etc.) ─
//
// Store the *hash* of the key, never the plaintext. The plaintext is returned
// once at creation time. Revocation = set `revokedAt`. The key plaintext
// should look like `tcx_<founderId>_<64-hex-random>` so the client can send
// the founderId bits without a DB lookup for routing, and the random tail is
// the secret. `authenticateApiKey()` in src/lib/apiKeyAuth.ts implements
// the verification (bcrypt compare against `keyHash`).
model ApiKey {
  id             String @id @default(cuid())
  organizationId String
  /// Founder the key acts on behalf of — uploads are attributed to them.
  founderId      String

  /// Human label shown in the management UI (e.g. "Dialectic on laptop").
  label   String
  /// Short prefix of the plaintext (first 12 chars) — shown in UI for identification.
  prefix  String
  /// bcrypt hash of the full plaintext key. Never store plaintext.
  keyHash String
  /// Comma-separated scopes (e.g. "upload:write"). Empty = full founder scope.
  scopes  String @default("")

  createdAt  DateTime  @default(now())
  lastUsedAt DateTime?
  revokedAt  DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
  @@index([prefix])
}

// ── Method ↔ Conclusion linkage ───────────────────────────────────────────
//
// Bridge table: which registered methods produced this conclusion, and at
// what relative weight. A single conclusion may compose several methods
// (e.g. "empirical_calibration" + "adversarial_revision"), so the weights
// are not constrained to sum to 1 — they're independent contributions in
// [0, 1]. The `domain` column lets the track-record aggregator group by
// the conclusion's topical domain so we don't smooth across forecasting,
// policy design, etc.
//
// Idempotent: the linker upserts on (conclusionId, methodName, methodVersion)
// rather than appending.

model ConclusionMethod {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  /// Reference into the in-process method registry. Stored as
  /// (name, version) rather than a foreign key because the registry is a
  /// Python decorator catalog, not a DB table.
  methodName    String
  methodVersion String

  /// In [0, 1]. How much this method contributed to the conclusion. The
  /// linker is allowed to assign multiple methods weight 1.0 — this is
  /// not a softmax over methods.
  weight Float @default(1.0)

  /// Domain the conclusion sits in (e.g. "forecasting", "policy"). Empty
  /// string when unknown. Track records are computed per-domain.
  domain String @default("")

  /// Free-form rationale from the linker (LLM judge or stub). Useful for
  /// audit; not load-bearing.
  rationale String @default("")

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion   Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([conclusionId, methodName, methodVersion])
  @@index([organizationId, methodName, methodVersion])
  @@index([methodName, methodVersion])
}

// ── Materialized per-method track record ─────────────────────────────────
//
// Rolled up from resolved ForecastPredictions linked to each method through
// ConclusionMethod, weighted by `ConclusionMethod.weight`. Materialized
// rather than computed on every page load because the join goes through a
// chain of three tables and the aggregation includes a bootstrap CI on the
// calibration slope. The materialization job (`noosphere methods
// track-record --rebuild`) is idempotent: it upserts on
// (organizationId, methodName, methodVersion, domain).
model MethodTrackRecord {
  id             String @id @default(cuid())
  organizationId String

  methodName    String
  methodVersion String

  /// Empty string for "no domain label". Track records are NEVER smoothed
  /// across domains — one row per domain.
  domain String @default("")

  /// Number of resolved ForecastPredictions feeding this row. Hard filter:
  /// unresolved predictions are excluded entirely.
  sampleSize Int

  /// Σ(weight·brier) / Σ(weight). Null when sampleSize == 0.
  weightedBrier Float?

  /// OLS slope of outcome ~ probability over resolved predictions, with a
  /// non-parametric bootstrap CI. Null when the slope is undefined
  /// (sampleSize < 2 or zero variance in probabilities).
  calibrationSlope       Float?
  calibrationSlopeCiLow  Float?
  calibrationSlopeCiHigh Float?

  /// Fraction of source conclusions whose MQS severity sub-score is at
  /// or above the published threshold (0.5). Null when no MQS data.
  severityPassRate Float?

  /// Audit blob: bootstrap iterations, threshold used, source ids, etc.
  evidence Json

  computedAt DateTime @default(now())
  createdAt  DateTime @default(now())
  updatedAt  DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@unique([organizationId, methodName, methodVersion, domain])
  @@index([methodName, methodVersion])
  @@index([organizationId, computedAt])
}

// ── Domain Bounds: per-method declarative applicability gates ───────────
//
// Each method registers a `DomainBound` (see
// noosphere/methods/domain_bounds.py) declaring the embedding region
// and/or topic-tag set in which it is allowed to operate. When a
// conclusion is run through a method, the orchestrator records the
// resulting verdict on `DomainBoundVerdict` so the UI can render an
// in-domain / edge / out badge and so MQS can gate the composite.
//
// Anchors are versioned. Re-curating produces a NEW `AnchorRevision`
// row rather than mutating the prior one — older `DomainBoundVerdict`
// rows continue to point at the revision that was active when they
// were emitted. Cross-model comparisons are refused: the
// `embeddingModel` on AnchorRevision must match the embedding model
// of the conclusion being checked.

model AnchorRevision {
  id             String @id @default(cuid())
  organizationId String

  /// Method this revision belongs to. Stored as (name, version) rather
  /// than a foreign key for the same reason `ConclusionMethod` does:
  /// the registry is a Python decorator catalog, not a DB table.
  methodName    String
  methodVersion String

  /// Stable content-hash id, e.g. `rev_8f...`. Used by
  /// `DomainBoundVerdict.anchorRevisionId` to pin a verdict to the
  /// exact anchors that were active when it ran.
  revisionId String

  /// Embedding model identifier these anchors were curated under.
  /// Cross-model comparisons are refused at check time.
  embeddingModel String

  /// k-medoid centroid vectors. JSON array of arrays: each inner array
  /// is one anchor of length `dim`.
  anchors Json

  /// Angular cosine thresholds. `inRadius` defines the in-domain
  /// region; `edgeRadius` (>= inRadius) the soft edge-case zone.
  inRadius   Float
  edgeRadius Float

  /// Free-form curator notes (which medoid IDs were inspected, why a
  /// radius was widened, etc.). Not load-bearing.
  notes String @default("")

  /// True when the revision is the active one for this method. Older
  /// revisions are kept (verdicts point at them) but never new
  /// verdicts. Exactly zero or one revision per method should be
  /// active at any time.
  active Boolean @default(false)

  createdAt DateTime @default(now())

  organization Organization        @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  verdicts     DomainBoundVerdict[]

  @@unique([organizationId, methodName, methodVersion, revisionId])
  @@index([organizationId, methodName, methodVersion, active])
}

model DomainBoundVerdict {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String

  methodName    String
  methodVersion String

  /// One of `in_bounds`, `edge_case`, `out_of_bounds`. Treated as the
  /// source of truth for `MethodologyQualityScore.domainSensitivity`.
  status String

  /// Signed margin: positive when in-bounds, negative when out. Units
  /// are angular cosine distance for anchor-driven verdicts and the
  /// binary {-1, +1} for pure tag verdicts.
  margin Float

  /// Free-form reason from the bound check. Hover text on the badge.
  reason String @default("")

  /// Optional pin: when the verdict came from an anchor bound, this
  /// links to the exact `AnchorRevision` that was active at run time.
  /// Null for tag-only verdicts.
  anchorRevisionId String?

  /// Tags that matched (when the tag side participated). Empty for
  /// pure anchor verdicts.
  matchedTags String[] @default([])

  /// Embedding model the verdict was computed under. Stored so a
  /// future model migration can detect verdicts that need to be
  /// recomputed.
  embeddingModel String?

  evidence Json?

  createdAt DateTime @default(now())

  organization   Organization    @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion     Conclusion      @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  anchorRevision AnchorRevision? @relation(fields: [anchorRevisionId], references: [id], onDelete: SetNull)

  @@unique([conclusionId, methodName, methodVersion])
  @@index([organizationId, methodName, methodVersion])
  @@index([status])
}

// ── Recalibration: per-domain isotonic mapping raw → calibrated ──────────
//
// The firm's stated confidence (a probability on a forecast, a confidence
// score on a conclusion) is what the producing model actually believes.
// `CalibrationModel` lets the public render that number conditionally on
// the firm's track record: each row is a domain-scoped isotonic
// regression fit over resolved binary forecasts, with a fit timestamp,
// sample size, and a SHA-256 hash of the canonicalized resolution set so
// a reader can pinpoint exactly which fit produced a displayed number.
//
// Lifecycle:
//   * Re-fit weekly by `_tick_recalibration` in
//     `noosphere/forecasts/scheduler.py`.
//   * The fitter inserts a NEW row each cycle and flips the previous
//     active row's `active` flag to false. Older rows are kept (audit)
//     but never become the source for a new render.
//   * Display path queries the active row for `(organizationId, domain)`;
//     when no row exists OR `sampleSize < threshold`, the conclusion /
//     forecast is rendered uncalibrated with a "small sample" tag.

model CalibrationModel {
  id             String @id @default(cuid())
  organizationId String

  /// Domain key (matches `ForecastMarket.category` / `ConclusionMethod.domain`).
  /// Calibration models are NEVER smoothed across domains: a strong-domain
  /// track record must not flatter a weak-domain confidence.
  domain String

  /// Monotonically increasing per (organizationId, domain). New fits get
  /// `MAX(version)+1`. The combination is unique so a re-fit cannot
  /// silently overwrite a prior model.
  version Int

  /// When the fit was computed.
  fitAt DateTime @default(now())

  /// Resolved binary forecasts that fed the fit. Below
  /// `THESEUS_RECALIBRATION_MIN_SAMPLES` the fitter does not write a row
  /// at all; the absence is the conservative-by-default signal.
  sampleSize Int

  /// SHA-256 hex over the canonicalized resolution set the fit was
  /// trained on. Lets the UI link a displayed calibrated number back to
  /// the exact training rows.
  resolutionHash String

  /// Piecewise-linear knots: `{"x": [...], "y": [...]}` with `x` ascending
  /// and `y` non-decreasing. The TS apply path interpolates linearly
  /// between knots and clamps outside.
  knots Json

  /// True for the row currently used to render. Exactly zero or one row
  /// per `(organizationId, domain)` should be active at any time.
  active Boolean @default(true)

  createdAt DateTime @default(now())

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@unique([organizationId, domain, version])
  @@index([organizationId, domain, active])
  @@index([organizationId, domain, fitAt])
}

// ── Recalibration override ─────────────────────────────────────────────
//
// A founder can opt a specific conclusion out of the recalibration
// display layer — useful when the conclusion is itself the subject of a
// methodology change (the firm is *deliberately* repricing how it
// calibrates), and applying the prior calibration would obscure rather
// than clarify what changed.
//
// The override row IS the audit trail: founder, timestamp, free-form
// reason. There is at most one override per conclusion (`@unique`); a
// later founder can edit the row to update the reason. Removing the
// override = deleting the row.

model RecalibrationOverride {
  id             String @id @default(cuid())
  organizationId String
  conclusionId   String @unique
  founderId      String

  /// Free-form reason (e.g. "methodology change in flight; raw is the
  /// signal we want readers to evaluate").
  reason String @default("")

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  conclusion   Conclusion   @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  founder      Founder      @relation(fields: [founderId], references: [id])

  @@index([organizationId])
  @@index([founderId])
}

