import Link from "next/link";
import { notFound } from "next/navigation";
import type { Metadata } from "next";

import PublicHeader from "@/components/PublicHeader";
import RespondCallout from "@/components/RespondCallout";
import { db } from "@/lib/db";
import { getFounder } from "@/lib/auth";
import {
  parsePublicationPayload,
  type PublishedConclusion,
} from "@/lib/conclusionsRead";
import { founderDisplayName } from "@/lib/founderDisplay";

/**
 * Public blog post — individual article page.
 *
 * Renders any Upload with `publishedAt IS NOT NULL AND slug = :slug`.
 * Unpublished uploads 404 (instead of leaking existence via an auth
 * redirect). Because the same underlying Upload row powers the private
 * founder workspace, no data is duplicated — the Codex's blog is
 * literally "a published view of the same artifact".
 *
 * Rendering philosophy: we aim for long-form legibility. The body is
 * the `textContent` (plain prose from the extractor), wrapped at
 * ~70 characters via CSS max-width, set in EB Garamond for the
 * reading voice. No distracting sidebars. A small "← Back" link at
 * the top. The author byline + date sit just under the title.
 *
 * If the upload has a `description` that's distinct from the extracted
 * textContent (e.g. a founder wrote a short intro), we use it as a
 * pull-quote lede; otherwise the body begins immediately.
 */

export const dynamic = "force-dynamic";
export const revalidate = 60;

type PageProps = { params: Promise<{ slug: string }> };

export async function generateMetadata({
  params,
}: PageProps): Promise<Metadata> {
  const { slug } = await params;
  const post = await db.upload.findFirst({
    where: {
      slug,
      publishedAt: { not: null },
      deletedAt: null,
      // Only "org"-visibility uploads appear on the public blog. See
      // app/page.tsx for the symmetric rule on the index.
      visibility: "org",
    },
    select: { title: true, blogExcerpt: true, description: true, textContent: true },
  });
  if (!post) return { title: "Post not found · Theseus Codex" };
  const desc = post.blogExcerpt || post.description || post.textContent || "";
  return {
    title: `${post.title} · Theseus Codex`,
    description: desc.slice(0, 160).replace(/\s+/g, " "),
    openGraph: {
      title: post.title,
      description: desc.slice(0, 240).replace(/\s+/g, " "),
      type: "article",
    },
  };
}

export default async function PostPage({ params }: PageProps) {
  const { slug } = await params;
  const founder = await getFounder();

  const post = await db.upload.findFirst({
    // Soft-deleted posts 404 rather than render, so a shared link for
    // a retracted post behaves the same as an unknown slug. The
    // `visibility: "org"` filter excludes both "private" (uploader-
    // only) and "semi-private" (firm-only) rows; by construction
    // these shouldn't coexist with a publish state, but enforcing it
    // here guarantees that even a stale slug cached in a post's URL
    // history can't pull the content back onto the public blog.
    where: {
      slug,
      publishedAt: { not: null },
      deletedAt: null,
      visibility: "org",
    },
    select: {
      id: true,
      organizationId: true,
      title: true,
      slug: true,
      description: true,
      authorBio: true,
      blogExcerpt: true,
      textContent: true,
      publishedAt: true,
      sourceType: true,
      // New podcast fields — when audioUrl is set we render an
      // <audio controls> player at the top of the post and label
      // the card/byline line with the episode duration.
      audioUrl: true,
      audioDurationSec: true,
      founder: { select: { displayName: true, name: true, username: true } },
    },
  });

  if (!post) {
    notFound();
  }

  const responseTarget = await responseTargetForPost(post, slug);

  const date = new Date(post.publishedAt!).toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });

  const body = post.textContent || "";
  const paragraphs = splitParagraphs(body);
  const byline = post.authorBio || founderDisplayName(post.founder);

  return (
    <main style={{ minHeight: "100vh" }}>
      <PublicHeader authed={Boolean(founder)} />

      <article
        style={{
          maxWidth: "720px",
          margin: "0 auto",
          padding: "3rem 1.75rem 5rem",
        }}
      >
        <Link
          href="/"
          className="mono"
          style={{
            fontSize: "0.6rem",
            letterSpacing: "0.28em",
            textTransform: "uppercase",
            color: "var(--amber-dim)",
            textDecoration: "none",
            marginBottom: "1.5rem",
            display: "inline-block",
          }}
        >
          ← Back to index
        </Link>

        <RespondCallout conclusions={[responseTarget]} />

        <header style={{ marginBottom: "2rem" }}>
          <p
            className="mono"
            style={{
              fontSize: "0.6rem",
              letterSpacing: "0.28em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              margin: "0 0 0.8rem",
            }}
          >
            {date} · {byline}
            {post.sourceType && post.sourceType !== "written"
              ? ` · ${post.sourceType}`
              : ""}
            {post.audioUrl ? (
              <span style={{ color: "var(--amber)" }}>
                {" · "}
                Episode
                {post.audioDurationSec
                  ? ` · ${formatDuration(post.audioDurationSec)}`
                  : ""}
              </span>
            ) : null}
          </p>
          <h1
            style={{
              fontFamily: "'EB Garamond', 'Iowan Old Style', Georgia, serif",
              fontSize: "clamp(1.85rem, 4.4vw, 2.6rem)",
              letterSpacing: "-0.005em",
              color: "var(--amber)",
              textShadow: "var(--glow-md)",
              margin: 0,
              lineHeight: 1.18,
              fontWeight: 600,
            }}
          >
            {post.title}
          </h1>
          {post.description ? (
            <p
              style={{
                fontFamily: "'EB Garamond', serif",
                fontStyle: "italic",
                fontSize: "1.18rem",
                color: "var(--parchment)",
                lineHeight: 1.55,
                margin: "1.25rem 0 0",
                borderLeft: "2px solid var(--amber-dim)",
                paddingLeft: "1rem",
              }}
            >
              {post.description}
            </p>
          ) : null}
        </header>

        {post.audioUrl ? (
          <section
            className="ascii-frame"
            data-label="AUDIO · EPISODE"
            style={{
              margin: "0 0 2rem",
              padding: "1.25rem 1.25rem 1rem",
              background:
                "linear-gradient(180deg, rgba(212,160,23,0.08), rgba(212,160,23,0.02))",
            }}
          >
            <p
              className="mono"
              style={{
                fontSize: "0.6rem",
                letterSpacing: "0.26em",
                textTransform: "uppercase",
                color: "var(--amber-dim)",
                margin: "0 0 0.6rem",
              }}
            >
              ◀︎ Listen {post.audioDurationSec
                ? `· ${formatDuration(post.audioDurationSec)}`
                : ""}
            </p>
            {/*
              Native HTML5 audio player — zero JS dependency, works on
              every modern browser + iOS Safari. We skip `preload="auto"`
              so the 30MB podcast file doesn't download until the
              visitor actually hits play.
            */}
            <audio
              controls
              preload="metadata"
              style={{ width: "100%" }}
              aria-label={`Audio for ${post.title}`}
            >
              <source src={post.audioUrl} />
              Your browser doesn&rsquo;t support HTML5 audio.{" "}
              <a
                href={post.audioUrl}
                style={{ color: "var(--amber)" }}
                target="_blank"
                rel="noopener noreferrer"
              >
                Download the file
              </a>
              .
            </audio>
            <p
              style={{
                fontFamily: "'EB Garamond', serif",
                fontStyle: "italic",
                fontSize: "0.9rem",
                color: "var(--parchment-dim)",
                margin: "0.75rem 0 0",
              }}
            >
              Transcript below — scroll to read, or hit play to listen.
            </p>
          </section>
        ) : null}

        <div
          className="post-body public-article-body"
          style={{
            fontFamily: "'EB Garamond', serif",
            color: "var(--parchment)",
            fontSize: "1.1rem",
            lineHeight: 1.7,
          }}
        >
          {paragraphs.length === 0 ? (
            <p style={{ color: "var(--parchment-dim)", fontStyle: "italic" }}>
              (This post has no body text. If it was ingested from audio,
              the transcript may still be processing.)
            </p>
          ) : (
            paragraphs.map((p, i) => (
              <p key={i} style={{ margin: "0 0 1.1rem" }}>
                {p}
              </p>
            ))
          )}
        </div>

        <footer
          style={{
            marginTop: "3rem",
            paddingTop: "1.2rem",
            borderTop: "1px solid var(--stroke)",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            flexWrap: "wrap",
            gap: "1rem",
          }}
        >
          <p
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.2em",
              textTransform: "uppercase",
              color: "var(--parchment-dim)",
              margin: 0,
            }}
          >
            {byline}
            <span style={{ opacity: 0.5 }}> · Theseus Codex</span>
          </p>
          <Link
            href="/"
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.22em",
              textTransform: "uppercase",
              color: "var(--amber)",
              textDecoration: "none",
            }}
          >
            More from the Codex →
          </Link>
        </footer>
      </article>
    </main>
  );
}

type PostResponseTargetInput = {
  id: string;
  organizationId: string;
  title: string;
  slug: string | null;
  publishedAt: Date | null;
};

type PublishedConclusionDbRow = {
  id: string;
  kind: string;
  slug: string;
  version: number;
  sourceConclusionId: string;
  publishedAt: Date | string;
  doi: string;
  zenodoRecordId: string;
  discountedConfidence: number;
  statedConfidence: number;
  calibrationDiscountReason: string;
  payloadJson: string;
};

async function responseTargetForPost(
  post: PostResponseTargetInput,
  routeSlug: string,
): Promise<PublishedConclusion> {
  const published = await db.publishedConclusion.findFirst({
    where: {
      organizationId: post.organizationId,
      OR: [
        { id: post.id },
        { sourceConclusionId: post.id },
        { sourceConclusionId: `article:${post.id}` },
        { slug: post.slug ?? routeSlug },
      ],
    },
    orderBy: { publishedAt: "desc" },
    select: {
      id: true,
      kind: true,
      slug: true,
      version: true,
      sourceConclusionId: true,
      publishedAt: true,
      doi: true,
      zenodoRecordId: true,
      discountedConfidence: true,
      statedConfidence: true,
      calibrationDiscountReason: true,
      payloadJson: true,
    },
  });

  return published
    ? publishedConclusionFromRow(published as PublishedConclusionDbRow)
    : fallbackPostResponseTarget(post, routeSlug);
}

function publishedConclusionFromRow(row: PublishedConclusionDbRow): PublishedConclusion {
  return {
    id: row.id,
    kind: row.kind,
    slug: row.slug,
    version: row.version,
    sourceConclusionId: row.sourceConclusionId,
    publishedAt:
      row.publishedAt instanceof Date
        ? row.publishedAt.toISOString()
        : new Date(row.publishedAt).toISOString(),
    doi: row.doi,
    zenodoRecordId: row.zenodoRecordId,
    discountedConfidence: row.discountedConfidence,
    statedConfidence: row.statedConfidence,
    calibrationDiscountReason: row.calibrationDiscountReason,
    payload: parsePublicationPayload(row),
  };
}

function fallbackPostResponseTarget(
  post: PostResponseTargetInput,
  routeSlug: string,
): PublishedConclusion {
  const publishedAt = post.publishedAt
    ? post.publishedAt.toISOString()
    : new Date().toISOString();
  const slug = post.slug ?? routeSlug;

  return {
    id: post.id,
    kind: "POST",
    slug,
    version: 1,
    sourceConclusionId: `post:${post.id}`,
    publishedAt,
    doi: "",
    zenodoRecordId: "",
    discountedConfidence: 0,
    statedConfidence: 0,
    calibrationDiscountReason: "",
    payload: {
      schema: "theseus.publicConclusion.v1",
      conclusionText: `Respond to this post: ${post.title}`,
      rationale: "",
      topicHint: "",
      evidenceSummary: "",
      exitConditions: [],
      strongestObjection: { objection: "", firmAnswer: "" },
      openQuestionsAdjacent: [],
      voiceComparisons: [],
      methodology: {
        schema: "theseus.methodology.v1",
        reviewerNarrative: "",
        profiles: [],
      },
      timeline: [],
      whatWouldChangeOurMind: [],
      citations: [],
    },
  };
}

/**
 * Format a duration in seconds as `MM:SS` or `H:MM:SS` — what a podcast
 * app would show next to the play button.
 */
function formatDuration(seconds: number): string {
  const total = Math.max(0, Math.floor(seconds));
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const mm = m.toString().padStart(2, "0");
  const ss = s.toString().padStart(2, "0");
  return h > 0 ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
}

/**
 * Split prose into paragraphs. A "paragraph" is a block separated by
 * one-or-more blank lines. We also soft-split runs of plain single-line
 * content into paragraphs if they're long enough to warrant breaks —
 * but only when there are ZERO paragraph-break signals, so we don't
 * double-split well-formed text.
 */
function splitParagraphs(text: string): string[] {
  const trimmed = text.trim();
  if (!trimmed) return [];
  // Primary split: double-newline paragraph breaks (the normal case).
  const blocks = trimmed.split(/\n\s*\n+/);
  if (blocks.length > 1) {
    return blocks
      .map((b) => b.trim().replace(/\s+/g, " "))
      .filter(Boolean);
  }
  // Fallback: treat every 3–4 sentences as a paragraph so a long
  // one-line dump doesn't become an unreadable wall. 400 chars is a
  // reasonable paragraph in EB Garamond at 1.1rem.
  const SENT = /([^.!?]+[.!?]+)\s+(?=[A-Z])/g;
  const sentences = trimmed.replace(SENT, "$1\n").split(/\n/);
  const out: string[] = [];
  let buf = "";
  for (const s of sentences) {
    buf = buf ? buf + " " + s.trim() : s.trim();
    if (buf.length >= 400) {
      out.push(buf);
      buf = "";
    }
  }
  if (buf) out.push(buf);
  return out.length > 0 ? out : [trimmed];
}

"""CLI commands for the Method Registry subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _render(obj, as_json: bool) -> None:
    if as_json:
        click.echo(json.dumps(obj, indent=2, default=str))


@click.group("methods")
def cli() -> None:
    """Method registry: list, inspect, run, and diff registered methods."""


@cli.command("list")
@click.option("--status", "status_filter", type=str, default=None,
              help="Filter by status (experimental, active, deprecated, retired)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def list_methods(status_filter: Optional[str], as_json: bool) -> None:
    """List all registered methods."""
    from noosphere.methods import REGISTRY

    methods = REGISTRY.list(status_filter=status_filter)
    if as_json:
        _render([{"name": m.name, "version": m.version, "status": m.status,
                  "type": m.method_type.value, "description": m.description}
                 for m in methods], True)
        return
    if not methods:
        console.print("[yellow]No methods registered.[/yellow]")
        return
    table = Table(title="Registered Methods", show_header=True)
    table.add_column("Name", style="cyan")
    table.add_column("Version")
    table.add_column("Status")
    table.add_column("Type")
    table.add_column("Description", max_width=50)
    for m in methods:
        table.add_row(m.name, m.version, m.status, m.method_type.value,
                      m.description[:50])
    console.print(table)


@cli.command("show")
@click.argument("ref")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def show_method(ref: str, as_json: bool) -> None:
    """Show details of a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    method, _fn = REGISTRY.get(name, version=version)
    if as_json:
        _render(method.model_dump(), True)
        return
    table = Table(title=f"Method: {method.name}@{method.version}", show_header=False)
    for field in ("method_id", "name", "version", "method_type", "status",
                  "owner", "description", "rationale"):
        val = getattr(method, field)
        table.add_row(field, str(val) if not hasattr(val, "value") else val.value)
    table.add_row("preconditions", ", ".join(method.preconditions) or "—")
    table.add_row("postconditions", ", ".join(method.postconditions) or "—")
    console.print(table)


@cli.command("run")
@click.argument("ref")
@click.option("--input", "input_json", required=True, help="JSON input for the method")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def run_method(ref: str, input_json: str, as_json: bool) -> None:
    """Run a method. REF is name or name@version."""
    from noosphere.methods import REGISTRY

    name, version = (ref.split("@", 1) + ["latest"])[:2]
    _method, fn = REGISTRY.get(name, version=version)
    payload = json.loads(input_json)
    result = fn(payload)
    if as_json:
        _render(result if isinstance(result, (dict, list)) else str(result), True)
        return
    console.print(result)


@cli.command("diff")
@click.argument("ref_a")
@click.argument("ref_b")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def diff_methods(ref_a: str, ref_b: str, as_json: bool) -> None:
    """Diff two method versions. Each REF is name@version."""
    from noosphere.methods import REGISTRY

    name_a, ver_a = (ref_a.split("@", 1) + ["latest"])[:2]
    name_b, ver_b = (ref_b.split("@", 1) + ["latest"])[:2]
    m_a, _ = REGISTRY.get(name_a, version=ver_a)
    m_b, _ = REGISTRY.get(name_b, version=ver_b)
    d_a, d_b = m_a.model_dump(), m_b.model_dump()
    diffs = {k: {"old": d_a[k], "new": d_b[k]}
             for k in d_a if d_a.get(k) != d_b.get(k)}
    if as_json:
        _render(diffs, True)
        return
    if not diffs:
        console.print("[green]Methods are identical.[/green]")
        return
    table = Table(title=f"Diff: {ref_a} ↔ {ref_b}", show_header=True)
    table.add_column("Field", style="cyan")
    table.add_column("Old")
    table.add_column("New")
    for field, vals in diffs.items():
        table.add_row(field, str(vals["old"])[:60], str(vals["new"])[:60])
    console.print(table)


