    createdAt: string;
    updatedAt: string;
    target: {
      id: string;
      text: string;
      topicHint: string;
      confidenceTier: string;
      confidence: number;
      createdAt: string;
      methodologyProfiles: PublicationMethodologyProfile[];
    };
    reviewer: {
      id: string;
      displayName: string | null;
      name: string;
